async (page) => {
  const fs = require('fs');
  const path = require('path');
  // close first-run wizard if present
  try {
    await page.evaluate(() => {
      const ids = ['#firstrunwizard', '#colorbox', '#cboxOverlay'];
      ids.forEach(sel => {
        const el = document.querySelector(sel);
        if (el) el.remove();
      });
      document.body.classList.remove('stop-scrolling');
    });
  } catch (e) {}

  // ensure we're logged in; if login form visible, log in
  const userInput = page.locator('input[name="user"], input#user');
  if (await userInput.count()) {
    await userInput.first().fill('theagentcompany');
    const passInput = page.locator('input[name="password"], input#password');
    await passInput.first().fill('theagentcompany');
    await Promise.all([
      page.waitForLoadState('networkidle'),
      page.locator('input[type="submit"], button[type="submit"], #submit').first().click()
    ]);
  }

  // navigate to Documents/Data Analysis
  await page.waitForLoadState('domcontentloaded');
  const filesApp = 'http://the-agent-company.com:8092/index.php/apps/files/?dir=/Documents/Data%20Analysis';
  await page.goto(filesApp, { waitUntil: 'domcontentloaded' });
  await page.waitForTimeout(1500);

  // remove overlay again if it came back
  await page.evaluate(() => {
    const ids = ['#firstrunwizard', '#colorbox', '#cboxOverlay'];
    ids.forEach(sel => {
      const el = document.querySelector(sel);
      if (el) el.remove();
    });
  });

  // find row/link for beverage_stats.xlsx
  const row = page.locator('tr[data-file*="beverage_stats.xlsx"], tr:has(a.name="beverage_stats.xlsx"), tr:has(span.nametext:text("beverage_stats.xlsx"))').first();
  if (!(await row.count())) {
    // fallback: generic link search
    const fallback = page.locator('a.name:text("beverage_stats.xlsx"), span.nametext:text("beverage_stats.xlsx")').first();
    if (!(await fallback.count())) throw new Error('beverage_stats.xlsx not found in Data Analysis');
  }

  // Try to get direct download URL
  let downloadUrl = await row.getAttribute('data-download');
  if (!downloadUrl) {
    // try action menu data attributes
    downloadUrl = await page.evaluate(() => {
      const tr = [...document.querySelectorAll('tr')].find(r => (r.getAttribute('data-file')||'').includes('beverage_stats.xlsx') || (r.textContent||'').includes('beverage_stats.xlsx'));
      if (!tr) return null;
      return tr.getAttribute('data-download') || tr.dataset?.download || null;
    });
  }

  if (!downloadUrl) {
    // construct WebDAV download URL as fallback
    downloadUrl = 'http://the-agent-company.com:8092/remote.php/dav/files/theagentcompany/Documents/Data%20Analysis/beverage_stats.xlsx';
  } else if (downloadUrl.startsWith('/')) {
    downloadUrl = 'http://the-agent-company.com:8092' + downloadUrl;
  }

  const context = page.context();
  const cookies = await context.cookies();
  const cookieHeader = cookies.map(c => `${c.name}=${c.value}`).join('; ');

  const response = await page.request.get(downloadUrl, {
    headers: {
      'cookie': cookieHeader
    }
  });

  if (!response.ok()) {
    throw new Error(`Download failed ${response.status()} from ${downloadUrl}`);
  }

  const buffer = await response.body();
  const outPath = '/workspace/beverage_stats.xlsx';
  fs.writeFileSync(outPath, buffer);

  return { outPath, bytes: buffer.length, downloadUrl, status: response.status() };
}

